import { useState } from 'react';
import FixturesArray from '../../components/data/fixtures'
import ResultsRow from './resultsrow'
import AddFixture from '../fixture/fixture';

const ResultsGrid = ({viewFixture} : any) => {

    // useState is a hook. Must be first line of the function. 
    // useState(xxx) - xxx is the original collection
    // [fixtures,...] - fixtures is the current copy of it. This will get updated by using setFixture
    // [..., setFixture] - is a function used to update the fixtures array.
    const [fixtures, setFixture] = useState(FixturesArray);
    // function we are using to add a fixture. 
    // const addFixture = () =>
    // {
    //     // // Using the setFixture function, pass in the current fixtures (deconstructing it here)
    //     // // this will create a new array with whats in fixtures, then it will add what comes next
    //     // setFixture([
    //     //     ...fixtures,
    //     //     {
    //     //         id: 1,
    //     //         date: "9th September",
    //     //         result: "W",
    //     //         homeTeam: "Walton MK Kestrels",
    //     //         awayTeam: "Tigers",
    //     //         homeScore: 0,
    //     //         awayScore: 8,
    //     //         fixture: "League"
    //     //     },
    //     // ]);
    // }
    return(
        <>            
            <table className="table table-hover">
                <thead>
                    <tr>
                        <th>Date</th>
                        <th></th>
                        <th>Home Team</th>
                        <th></th>
                        <th></th>
                        <th>Away Team</th>
                        <th>Type</th>
                    </tr>
                </thead>
                <tbody>
                    {fixtures.map(f => <ResultsRow key={f.id} fixture={f} viewFixture={viewFixture}/>)}
                </tbody>
            </table>              
            <AddFixture currentFixtures={fixtures} setFixtureIntoArray={setFixture}/>
        </>
    );
}
export default ResultsGrid;
